CREATE OR REPLACE FUNCTION get_partition_count(table_name text)
RETURNS bigint AS $$
DECLARE
	count bigint;
BEGIN
	SELECT COUNT(*)
	INTO count
	FROM pg_inherits
	JOIN pg_class parent ON pg_inherits.inhparent = parent.oid
	WHERE parent.relname = table_name;
	RETURN count;
END;
$$ LANGUAGE plpgsql;
